module RefModule(
  input clk, reset,
  output reg [SIZE-1:0] out
);parameter SIZE = 4;

  reg [SIZE-1:0] pipeline_reg;

  always @(posedge clk, posedge reset)
    begin
      if (reset) begin
        pipeline_reg <= 0;
        out <= 0;
      end
      else begin
        pipeline_reg <= {pipeline_reg[SIZE-2:0], (pipeline_reg[SIZE-1] ^ pipeline_reg[SIZE-2])}; // Fixed the bit width issue here
        out <= pipeline_reg;
      end
    end

endmodule
